import { ChangeDetectionStrategy, Component, computed, inject, signal, viewChild } from '@angular/core';
import { Router } from '@angular/router';
import {
  ConfirmationDialogService,
  GridPageTitleComponent,
  ServerGridComponent,
} from '@nxgn-solutions/ui';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { type ColDef, type RowDoubleClickedEvent } from 'ag-grid-community';

import { GRID_ENDPOINTS } from '../../../core/grid/grid-endpoints';
import {
  getSelectedServerRows,
  SERVER_GRID_DEFAULT_COL_DEF,
  SERVER_GRID_PAGE_SIZE,
  SERVER_GRID_PAGE_SIZE_SELECTOR,
  type ServerGridSelection,
  tenantScopedServerGridFields,
} from '../../../core/grid/server-grid';
import { WorkflowGridItemDTO } from './workflow.models';
import { WorkflowService } from './workflow.service';

@Component({
  selector: 'app-workflow-list',
  standalone: true,
  imports: [GridPageTitleComponent, ServerGridComponent, TranslatePipe],
  templateUrl: './workflow-list.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class WorkflowListComponent {
  private readonly confirmationDialogService = inject(ConfirmationDialogService);
  private readonly router = inject(Router);
  private readonly translate = inject(TranslateService);
  private readonly workflowService = inject(WorkflowService);
  private readonly grid = viewChild<ServerGridComponent<WorkflowGridItemDTO>>('grid');

  readonly selectedRows = signal<WorkflowGridItemDTO[]>([]);
  readonly selectedItems = computed(() => this.selectedRows().map(row => ({ id: row.id })));
  readonly isGridDegraded = computed(() => Boolean(this.grid()?.persistentErrorMessage()));
  readonly errorMessage = signal<string | null>(null);

  readonly gridEndpoint = GRID_ENDPOINTS.workflows;
  readonly gridDefaultColDef = SERVER_GRID_DEFAULT_COL_DEF;
  readonly gridPageSize = SERVER_GRID_PAGE_SIZE;
  readonly gridPageSizeSelector = SERVER_GRID_PAGE_SIZE_SELECTOR;
  readonly gridExtraFields = tenantScopedServerGridFields(() => ({}));

  readonly columnDefs = computed<ColDef<WorkflowGridItemDTO>[]>(() => [
    { field: 'name', headerName: this.translate.instant('workflows.list.columns.name'), flex: 1.8 },
    { field: 'version', headerName: this.translate.instant('workflows.list.columns.version'), flex: 0.6 },
  ]);

  onSelectionChanged(event: ServerGridSelection<WorkflowGridItemDTO>): void {
    if (this.isGridDegraded()) {
      this.clearSelection();
      return;
    }

    this.selectedRows.set(getSelectedServerRows(event));
  }

  onRowDoubleClicked(event: RowDoubleClickedEvent<WorkflowGridItemDTO>): void {
    if (!this.isGridDegraded() && event.data) {
      void this.router.navigate(['/admin/workflows', event.data.id]);
    }
  }

  onAdd(): void {
    if (!this.isGridDegraded()) {
      void this.router.navigate(['/admin/workflows/new']);
    }
  }

  onEdit(): void {
    const selected = this.selectedRows();
    if (!this.isGridDegraded() && selected.length === 1) {
      void this.router.navigate(['/admin/workflows', selected[0].id]);
    }
  }

  async onDelete(): Promise<void> {
    const selected = this.selectedRows();
    if (this.isGridDegraded() || selected.length === 0) {
      return;
    }

    const confirmed = await this.confirmationDialogService.confirm(
      this.translate.instant('workflows.list.deleteMessage', { count: selected.length }),
      this.translate.instant('workflows.list.deleteTitle'),
      { variant: 'danger' },
    );

    if (!confirmed) {
      return;
    }

    try {
      for (const row of selected) {
        await this.workflowService.deleteDraft(row.id, { rowVersion: row.rowVersion ?? null });
      }
      this.refreshGrid();
    } catch {
      this.refreshGrid();
      this.errorMessage.set(this.translate.instant('workflows.list.deleteError'));
    }
  }

  private refreshGrid(): void {
    this.clearSelection();
    this.grid()?.refresh();
  }

  private clearSelection(): void {
    this.selectedRows.set([]);
  }
}

