private readonly route = inject(ActivatedRoute);

workflowFilter = signal<string | null>(null);

async ngOnInit(): Promise<void> {
  const params = this.route.snapshot.queryParams;
  if (params['workflow']) {
    this.workflowFilter.set(params['workflow']);
  }
  await this.load();
}

private async load(): Promise<void> {
  this.loading.set(true);
  try {
    const result = await this.actionService.getGridList(
      1, 100, undefined, this.workflowFilter() ?? undefined,
    );
    this.dataItems.set(result.items);
    this.totalCount.set(result.totalCount);
  } finally {
    this.loading.set(false);
  }
}

onClearFilter(): void {
  this.workflowFilter.set(null);
  this.router.navigate([], { queryParams: {} });
  this.load();
}

@if (workflowFilter()) {
  <div class="alert alert-info d-flex align-items-center justify-content-between mb-3">
    <span>{{ 'actions.list.filteredBy' | translate:{ workflow: workflowFilter() } }}</span>
    <button type="button" class="btn btn-sm btn-outline-secondary" (click)="onClearFilter()">
      {{ 'common.clearFilter' | translate }}
    </button>
  </div>
}

// State
page = signal(1);
pageSize = signal(25);

// Derived
totalPages = computed(() => Math.ceil(this.totalCount() / this.pageSize()));

// Data loading passes current page/pageSize
private async load(): Promise<void> {
  this.loading.set(true);
  try {
    const result = await this.actionService.getGridList(
      this.page(), this.pageSize(), this.searchTerm(),
    );
    this.dataItems.set(result.items);
    this.totalCount.set(result.totalCount);
  } finally {
    this.loading.set(false);
  }
}

// Page change handler — update signal and reload
onPageChange(newPage: number): void {
  this.page.set(newPage);
  this.load();
}

onPageSizeChange(newSize: number): void {
  this.pageSize.set(newSize);
  this.page.set(1);  // Reset to first page
  this.load();
}

@if (!loading() && totalCount() > pageSize()) {
  <div class="d-flex justify-content-between align-items-center mt-3">
    <span class="text-muted">
      {{ 'common.showingRange' | translate:{
        from: (page() - 1) * pageSize() + 1,
        to: page() * pageSize() > totalCount() ? totalCount() : page() * pageSize(),
        total: totalCount()
      } }}
    </span>
    <nav>
      <ul class="pagination pagination-sm mb-0">
        <li class="page-item" [class.disabled]="page() === 1">
          <button class="page-link" (click)="onPageChange(page() - 1)">&laquo;</button>
        </li>
        @for (p of [].constructor(totalPages()); track $index) {
          <li class="page-item" [class.active]="$index + 1 === page()">
            <button class="page-link" (click)="onPageChange($index + 1)">{{ $index + 1 }}</button>
          </li>
        }
        <li class="page-item" [class.disabled]="page() === totalPages()">
          <button class="page-link" (click)="onPageChange(page() + 1)">&raquo;</button>
        </li>
      </ul>
    </nav>
  </div>
}

