async onResolveConsultation(consultation: ConsultationDTO): Promise<void> {
  const confirmed = await this.confirmService.confirm(
    await firstValueFrom(this.translate.get('consultations.list.resolveMessage')),
    await firstValueFrom(this.translate.get('consultations.list.resolveTitle')),
    { variant: 'danger', confirmLabel: 'Resolve' },
  );
  if (!confirmed) return;

  try {
    await this.consultationService.resolve(consultation.id);
    this.toastr.success(
      await firstValueFrom(this.translate.get('consultations.list.resolveSuccess')),
    );
    await this.load();
  } catch {
    this.toastr.error(
      await firstValueFrom(this.translate.get('consultations.list.resolveError')),
    );
  }
}
